mapper.select:
select *
from store_member
where store_id = #{storeId}
  and member_bno = #{memberBno}
  and chk = 1
limit 1

select count(*)
from fill_apply
where fill_bno = #{fillBno}
  and id = #{id}
  and chk in (0, 1, 2)

select fa.*
from fill_apply fa
join fill f on f.bno = fa.fill_bno
join store s on s.store_code = f.code
where s.store_id = #{storeId}
  and fa.fill_bno = #{fillBno}
  and fa.bno = #{applyBno}
limit 1

mapper.update:
update fill
set chk = #{chk}
where bno = #{fillBno}

update fill_apply
set chk = #{chk}
where bno = #{applyBno}

update fill_apply
set chk = #{chk}
where fill_bno = #{fillBno}
  and bno != #{winnerApplyBno}
  and chk = 0

update fill_apply
set chk = 3
where fill_bno = #{fillBno}
  and id = #{id}
  and chk = 0
